files.content:
.mrg-link {
  align-items: baseline;
  box-sizing: border-box;
  color: var(--mrg-semantic-color-brand-action);
  display: inline-flex;
  font: inherit;
  gap: var(--mrg-semantic-space-inline-xs);
  max-inline-size: 100%;
  min-inline-size: 0;
  text-decoration-line: underline;
  text-decoration-thickness: var(--mrg-semantic-border-width-default);
  text-underline-offset: var(--mrg-semantic-space-inline-xs);
  transition:
    color var(--mrg-semantic-motion-duration-feedback) var(--mrg-semantic-motion-easing-standard),
    text-decoration-thickness var(--mrg-semantic-motion-duration-feedback)
      var(--mrg-semantic-motion-easing-standard);
}

.mrg-link:hover {
  text-decoration-thickness: var(--mrg-semantic-border-width-strong);
}

.mrg-link:active {
  color: var(--mrg-semantic-color-foreground-primary);
}

.mrg-link:focus-visible {
  border-radius: var(--mrg-component-focus-indicator-radius);
  box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
    var(--mrg-component-focus-indicator-contrast-background);
  outline: var(--mrg-component-focus-indicator-width) solid
    var(--mrg-component-focus-indicator-color);
  outline-offset: var(--mrg-component-focus-indicator-offset);
}

.mrg-link[data-current="true"] {
  color: var(--mrg-semantic-color-foreground-primary);
  font-weight: var(--mrg-semantic-font-weight-strong);
  text-decoration-style: double;
}

.mrg-link[data-standalone="true"] {
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: var(--mrg-semantic-size-target-preferred);
  padding-block: var(--mrg-semantic-space-inline-sm);
  padding-inline: var(--mrg-semantic-space-inline-xs);
}

.mrg-link [data-slot="link-label"] {
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-link [data-slot="link-external-indicator"],
.mrg-link [data-slot="link-download-indicator"] {
  flex: none;
  font-weight: var(--mrg-semantic-font-weight-strong);
  text-decoration: none;
}

.mrg-link [data-slot="link-external-context"] {
  background: var(--mrg-semantic-color-status-loading-background);
  border-radius: var(--mrg-semantic-radius-compact);
  color: var(--mrg-semantic-color-status-loading-foreground);
  font-size: var(--mrg-semantic-font-size-label);
  font-weight: var(--mrg-semantic-font-weight-label);
  padding-inline: var(--mrg-semantic-space-inline-xs);
  text-decoration: none;
}

@media (prefers-reduced-motion: reduce) {
  .mrg-link {
    transition: none;
  }
}

@media (forced-colors: active) {
  .mrg-link,
  .mrg-link[data-current="true"] {
    color: LinkText;
  }

  .mrg-link:visited {
    color: VisitedText;
  }

  .mrg-link [data-slot="link-external-context"] {
    background: Canvas;
    color: CanvasText;
  }
}

import { forwardRef, type AnchorHTMLAttributes, type ReactNode } from "react";

import "./link.css";

export type LinkCurrent = AnchorHTMLAttributes<HTMLAnchorElement>["aria-current"];

export interface LinkProps extends Omit<
  AnchorHTMLAttributes<HTMLAnchorElement>,
  "aria-disabled" | "href"
> {
  /** Required anchor destination passed directly to the native href attribute. */
  readonly href: string;
  /** Visible link label content and the default accessible-name source. */
  readonly children: ReactNode;
  /** Uses target=_blank by default and adds noopener and noreferrer to the resolved rel. */
  readonly external?: boolean;
  /** Expands standalone actions to the 44 CSS-pixel comfort target. */
  readonly standalone?: boolean;
  /** Optional visible and announced context such as "New tab". Rendered only for external links. */
  readonly externalContext?: string | false;
}

function mergeRel(rel: string | undefined, opensNewContext: boolean): string | undefined {
  if (!opensNewContext) return rel;
  const tokens = new Set((rel ?? "").split(/\s+/u).filter(Boolean));
  tokens.add("noopener");
  tokens.add("noreferrer");
  return [...tokens].join(" ");
}

export const Link = forwardRef<HTMLAnchorElement, LinkProps>(function Link(
  {
    children,
    className,
    download,
    external = false,
    externalContext = false,
    href,
    rel,
    standalone = false,
    target,
    ...nativeProps
  },
  ref,
) {
  const resolvedTarget = external ? (target ?? "_blank") : target;
  const usableExternalContext =
    external && typeof externalContext === "string" && externalContext.trim().length > 0
      ? externalContext
      : undefined;
  return (
    <a
      {...nativeProps}
      className={className === undefined ? "mrg-link" : `mrg-link ${className}`}
      data-current={nativeProps["aria-current"] === undefined ? undefined : "true"}
      data-download={download === undefined || download === false ? undefined : "true"}
      data-external={external || undefined}
      data-external-context={usableExternalContext === undefined ? undefined : "true"}
      data-slot="link"
      data-standalone={standalone || undefined}
      download={download}
      href={href}
      ref={ref}
      rel={mergeRel(rel, resolvedTarget === "_blank")}
      target={resolvedTarget}
    >
      <span data-slot="link-label">{children}</span>
      {usableExternalContext === undefined ? null : (
        <span data-slot="link-external-context">{usableExternalContext}</span>
      )}
      {external ? (
        <span aria-hidden="true" data-slot="link-external-indicator">
          ↗
        </span>
      ) : null}
      {download !== undefined && download !== false ? (
        <span aria-hidden="true" data-slot="link-download-indicator">
          ↓
        </span>
      ) : null}
    </a>
  );
});

Link.displayName = "Link";
Object.defineProperty(Link, Symbol.for("mergora-ui/toolbar-action"), { value: true });
